// --- utils.js ---
export const PI = 3.14159;
export function multiply(a, b) { return a * b; }
export function divide(a, b) { return a / b; }

// --- main.js ---
// We use exactly the names exported, inside curly braces.
// We only import what we actually need.
import { PI, multiply } from './utils.js';

// If there's a naming collision, we can rename it using 'as'
import { divide as div } from './utils.js';

// Import absolutely everything at once as an object
import * as mathTools from './utils.js';
console.log(mathTools.PI);

